import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../services/api";

function Login() {
  const navigate = useNavigate();

  const [formData, setFormData] = useState({
    email: "",
    password: "",
  });

  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleLogin = async (e) => {
    e.preventDefault();

    if (!formData.email || !formData.password) {
      alert("Please fill all fields");
      return;
    }

    try {
      setLoading(true);

      const response = await API.post("/auth/login", formData);

      if (response.data.status === "SUCCESS") {
        localStorage.setItem("userId", response.data.id);
        localStorage.setItem("username", response.data.username);
        localStorage.setItem("email", response.data.email);
        localStorage.setItem("role", response.data.role);

        if (response.data.role === "ADMIN") {
          navigate("/admin");
        } else {
          navigate("/home");
        }
      } else {
        alert(response.data.message || "Login failed");
      }
    } catch (error) {
      console.error("Login error:", error);
      alert(
        error.response?.data?.message ||
          "Login failed. Please check backend and credentials."
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.overlay}>
        <div style={styles.card}>
          <div style={styles.left}>
            <h1 style={styles.title}>Zoo Management System</h1>
            <p style={styles.subtitle}>
              Manage animals, enclosures, staff, feeding schedules, medical
              records, and users with one smart dashboard.
            </p>
          </div>

          <div style={styles.right}>
            <h2 style={styles.loginTitle}>Login</h2>

            <form onSubmit={handleLogin} style={styles.form}>
              <input
                type="email"
                name="email"
                placeholder="Enter email"
                value={formData.email}
                onChange={handleChange}
                style={styles.input}
              />

              <input
                type="password"
                name="password"
                placeholder="Enter password"
                value={formData.password}
                onChange={handleChange}
                style={styles.input}
              />

              <button type="submit" style={styles.button} disabled={loading}>
                {loading ? "Logging in..." : "Login"}
              </button>
            </form>

            <p style={styles.note}>
              Don’t have an account?{" "}
              <span style={styles.link} onClick={() => navigate("/register")}>
                Register
              </span>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    background:
      "linear-gradient(135deg, rgba(15,23,42,0.95), rgba(37,99,235,0.85))",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    padding: "20px",
    fontFamily: "Arial, sans-serif",
  },
  overlay: {
    width: "100%",
    display: "flex",
    justifyContent: "center",
  },
  card: {
    width: "100%",
    maxWidth: "1000px",
    background: "#ffffff",
    borderRadius: "24px",
    overflow: "hidden",
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    boxShadow: "0 15px 35px rgba(0,0,0,0.25)",
  },
  left: {
    background: "linear-gradient(135deg, #0f172a, #1d4ed8)",
    color: "#fff",
    padding: "60px 40px",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
  },
  title: {
    fontSize: "2.5rem",
    marginBottom: "20px",
  },
  subtitle: {
    fontSize: "1.05rem",
    lineHeight: "1.8",
    color: "rgba(255,255,255,0.9)",
  },
  right: {
    padding: "50px 40px",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
  },
  loginTitle: {
    fontSize: "2rem",
    marginBottom: "25px",
    color: "#111827",
  },
  form: {
    display: "flex",
    flexDirection: "column",
    gap: "16px",
  },
  input: {
    padding: "14px 16px",
    borderRadius: "10px",
    border: "1px solid #cbd5e1",
    fontSize: "1rem",
    outline: "none",
  },
  button: {
    background: "linear-gradient(90deg, #2563eb, #1d4ed8)",
    color: "#fff",
    border: "none",
    padding: "14px",
    borderRadius: "10px",
    fontSize: "1rem",
    cursor: "pointer",
    fontWeight: "bold",
  },
  note: {
    marginTop: "18px",
    color: "#6b7280",
    fontSize: "0.95rem",
  },
  link: {
    color: "#2563eb",
    fontWeight: "bold",
    cursor: "pointer",
  },
};

export default Login;
